public void clearThreadInterruptStatus() {
    Class<?> clazz = getTestClass().getJavaClass();
    try {
        synchronized (clazz) {
            Thread.interrupted();
        }
    } catch (InterruptedException e) {
        // Handle the InterruptedException if it occurs during synchronization
        e.printStackTrace();
    }
}

