public synchronized Object getListenerObject(Object listener) {
    // Check if the listener has the RunListener.ThreadSafe annotation
    boolean isThreadSafe = listener.getClass().isAnnotationPresent(RunListener.ThreadSafe.class);

    // If the listener is not thread-safe, create a new SynchronizedRunListener instance
    if (!isThreadSafe) {
        return new SynchronizedRunListener(listener, this);
    }

    // Return the existing listener object
    return listener;
}

